const body = $input.all()[0].json.body;
const uuidRegex = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;

if (!uuidRegex.test(body.tenantId)) {
  throw new Error('Invalid tenantId format');
}

if (!uuidRegex.test(body.factureId)) {
  throw new Error('Invalid factureId format');
}

const profils = ['MINIMUM', 'BASIC', 'EN16931'];
const profil = body.profil || 'MINIMUM';
if (!profils.includes(profil)) {
  throw new Error('Invalid profil: must be MINIMUM, BASIC, or EN16931');
}

return {
  tenantId: body.tenantId,
  factureId: body.factureId,
  profil: profil
};

